    var tabHook = useState(typeof stateInit.lastTopic === 'string' ? stateInit.lastTopic : 'home');
    var tab = tabHook[0], setTab = tabHook[1];
    var navSearchHook = useState('');
    var navSearch = navSearchHook[0], setNavSearch = navSearchHook[1];
    var libraryOpenHook = useState(false);
    var libraryOpen = libraryOpenHook[0], setLibraryOpen = libraryOpenHook[1];
    var comfortableReadingHook = useState(!!stateInit.comfortableReading);
    var comfortableReading = comfortableReadingHook[0], setComfortableReading = comfortableReadingHook[1];
    var learningProgressHook = useState({
      visitedTopics: stateInit.visitedTopics && typeof stateInit.visitedTopics === 'object' ? stateInit.visitedTopics : {},
      recentTopics: Array.isArray(stateInit.recentTopics) ? stateInit.recentTopics : [],
      bookmarkedTopics: Array.isArray(stateInit.bookmarkedTopics) ? stateInit.bookmarkedTopics : [],
      completedTopics: stateInit.completedTopics && typeof stateInit.completedTopics === 'object' ? stateInit.completedTopics : {},
      topicNotes: stateInit.topicNotes && typeof stateInit.topicNotes === 'object' ? stateInit.topicNotes : {}
    });
    var learningProgress = learningProgressHook[0], setLearningProgress = learningProgressHook[1];
    var noteDraftHook = useState('');
    var noteDraft = noteDraftHook[0], setNoteDraft = noteDraftHook[1];
    var learningNoticeHook = useState({ kind: 'info', message: 'Learning data is stored on this device. Download a backup if you need to move it.' });
    var learningNotice = learningNoticeHook[0], setLearningNotice = learningNoticeHook[1];
    var completedMissionsHook = useState(stateInit.completedMissions && typeof stateInit.completedMissions === 'object' ? stateInit.completedMissions : {});
    var completedMissions = completedMissionsHook[0], setCompletedMissions = completedMissionsHook[1];
    var scenarioHook = useState({ missionId: null, choiceIndex: null, reflection: '' });
    var activeScenario = scenarioHook[0], setActiveScenario = scenarioHook[1];
    var quizCheckpointResultsHook = useState(stateInit.quizCheckpointResults && typeof stateInit.quizCheckpointResults === 'object' ? stateInit.quizCheckpointResults : {});
    var quizCheckpointResults = quizCheckpointResultsHook[0], setQuizCheckpointResults = quizCheckpointResultsHook[1];
    var regionHook = useState(stateInit.region);
    var region = regionHook[0], setRegion = regionHook[1];
    var simHook = useState({ active: false, threeLoaded: !!window.THREE, threeError: false, loading: false });
    var sim = simHook[0], setSim = simHook[1];
    var hudHook = useState({});
    var hud = hudHook[0], setHud = hudHook[1];
    var statusHook = useState([]);
    var status = statusHook[0], setStatus = statusHook[1];
    var probeHook = useState(stateInit.probeReadings || []);
    var probes = probeHook[0], setProbes = probeHook[1];
    var droppersHook = useState(stateInit.droppersDeployed || 0);
    var droppersDeployed = droppersHook[0], setDroppers = droppersHook[1];
    var canvasRef = useRef(null);
    var farmRef = useRef(null);
    var topicSearchRef = useRef(null);
    var contentRef = useRef(null);
    var firstContentRenderRef = useRef(true);

    var initTimerRef = useRef(null);
    var controlPulseTimersRef = useRef({});
    useEffect(function() {
      var s = loadState();
      s.region = region;
      saveState(s);
    }, [region]);
    useEffect(function() {
      var s = loadState();
      s.comfortableReading = comfortableReading;
      saveState(s);
    }, [comfortableReading]);
    useEffect(function() {
      function onLabNavigationKeyDown(event) {
        if (event.defaultPrevented || event.altKey || event.ctrlKey || event.metaKey) return;
        var target = event.target;
        var isTyping = target && target.matches && target.matches('input, textarea, select, [contenteditable="true"]');
        if (event.key === '/' && !isTyping) {
          event.preventDefault();
          setLibraryOpen(true);
          setTimeout(function() {
            if (topicSearchRef.current && topicSearchRef.current.focus) topicSearchRef.current.focus();
          }, 0);
        } else if (event.key === 'Escape' && libraryOpen && !isTyping) {
          event.preventDefault();
          setLibraryOpen(false);
          aqAnnounce('Topic library closed');
        }
      }
      document.addEventListener('keydown', onLabNavigationKeyDown);
      return function() { document.removeEventListener('keydown', onLabNavigationKeyDown); };
    }, [libraryOpen]);
    useEffect(function() {
      if (firstContentRenderRef.current) {
        firstContentRenderRef.current = false;
        return;
      }
      var focusTimer = setTimeout(function() {
        var content = contentRef.current;
        if (!content) return;
        try { content.focus({ preventScroll: true }); } catch (_) { try { content.focus(); } catch (focusError) {} }
        var reduceMotion = !!(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches);
        try { content.scrollIntoView({ behavior: reduceMotion ? 'auto' : 'smooth', block: 'start' }); } catch (_) { content.scrollIntoView(); }
      }, 0);
      return function() { clearTimeout(focusTimer); };
    }, [tab]);

    function pushStatus(ev) {
      setStatus(function(prev) { return (prev || []).concat([ev]).slice(-8); });
      if (ev.type === 'probe') {
        setProbes(function(prev) {
          var ns = (prev || []).concat([ev.reading]).slice(-50);
          var s2 = loadState();
          s2.probeReadings = ns;
          saveState(s2);
          return ns;
        });
      }
      if (ev.type === 'dropper') {
        setDroppers(function(c) {
          var nv = typeof ev.count === 'number' ? ev.count : c + 1;
          var s2 = loadState();
          s2.droppersDeployed = nv;
          saveState(s2);
          return nv;
        });
      }
      if (ev.type === 'complete') {
        var s3 = loadState();
        s3.completedMissions = s3.completedMissions || {};
        s3.completedMissions['mission-1'] = { completedAt: Date.now(), mode: '3d' };
        saveState(s3);
        setCompletedMissions(Object.assign({}, s3.completedMissions));
      }
    }

    function startSim() {
      function actuallyStart() {
        setSim({ active: true, threeLoaded: true, threeError: false, loading: false });
        if (initTimerRef.current) clearTimeout(initTimerRef.current);
        initTimerRef.current = setTimeout(function() {
          initTimerRef.current = null;
          var c = canvasRef.current;
          if (!c) {
            setSim({ active: false, threeLoaded: true, threeError: true, loading: false });
            return;
          }
          if (farmRef.current && farmRef.current.dispose) farmRef.current.dispose();
          try {
            farmRef.current = initFarmSim(c, {
              onHudUpdate: setHud,
              onStatus: pushStatus,
              initialDroppers: loadState().droppersDeployed || 0,
              onExit: stopSim
            });
            if (!farmRef.current) throw new Error('Farm simulation failed to initialize');
            try { c.focus(); } catch (focusError) {}
            aqAnnounce('AquacultureLab 3D sim launched. Focus is in the farm view. WASD or arrow keys steer, F drops a seeded line at the lease, P takes a water-quality probe reading, and Escape exits.');
          } catch (err) {
            console.error('[Aquaculture] WebGL / 3D initialization failed:', err);
            setSim({ active: false, threeLoaded: false, threeError: true, loading: false });
          }
        }, 0);
      }
      if (window.THREE) actuallyStart();
      else {
        setSim(function(s) { return Object.assign({}, s, { loading: true }); });
        ensureThreeJS(actuallyStart, function() {
          setSim({ active: false, threeLoaded: false, threeError: true, loading: false });
          aqAnnounce('3D engine could not load. Use Chart Mode (2D fallback) instead.');
        });
      }
    }
    function stopSim() {
      if (initTimerRef.current) clearTimeout(initTimerRef.current);
      initTimerRef.current = null;
      clearFarmControlPulses();
      if (farmRef.current && farmRef.current.dispose) farmRef.current.dispose();
      farmRef.current = null;
      setSim({ active: false, threeLoaded: !!window.THREE, threeError: false, loading: false });
    }

    function setFarmControl(key, active) {
      if (farmRef.current && farmRef.current.setControl) farmRef.current.setControl(key, active);
    }
    function clearFarmControlPulses() {
      var timers = controlPulseTimersRef.current || {};
      Object.keys(timers).forEach(function(key) { clearTimeout(timers[key]); });
      controlPulseTimersRef.current = {};
    }
    function pulseFarmControl(key) {
      setFarmControl(key, true);
      var timers = controlPulseTimersRef.current;
      if (timers[key]) clearTimeout(timers[key]);
      timers[key] = setTimeout(function() {
        setFarmControl(key, false);
        delete timers[key];
      }, 180);
    }

    useEffect(function() {
      return function() {
        if (initTimerRef.current) clearTimeout(initTimerRef.current);
        if (farmRef.current && farmRef.current.dispose) farmRef.current.dispose();
        clearFarmControlPulses();
      };
    }, []);

