    var HATCHERY_PROTOCOLS = [
      { phase: '1. Broodstock conditioning (12-24 weeks pre-spawn)', detail: 'Adult oysters or mussels selected for size, color, vigor. Held in conditioning tanks at controlled temperature (start cool ~10°C, raise to spawning temp ~22°C over weeks). Fed extra phytoplankton.', equipment: 'Conditioning tanks (200-1000 gal), heaters, chiller, algae culture system', risk: 'Spawning out of sequence; loss of broodstock health' },
      { phase: '2. Spawning + fertilization', detail: 'Triggered by temperature shock or chemistry. Females release eggs; males release sperm. Fertilization occurs in tank. ~10-100 million eggs per spawn (oyster); 1-10 million (mussel).', equipment: 'Spawning trays, sieves, microscope', risk: 'Polyspermy (too many sperm) reduces fertilization rate; contamination' },
      { phase: '3. Larval rearing (10-21 days post-fertilization)', detail: 'Larvae held in conical tanks. Fed cultured microalgae (Isochrysis, Tetraselmis, Pavlova). Frequent water changes; temperature 22-26°C. Tracked daily — size + behavior.', equipment: 'Conical larval tanks, algae paste/cultures, microscope, water-quality probes', risk: 'Bacterial bloom; algae shortage; thermal shock' },
      { phase: '4. Settlement / metamorphosis (12-21 days)', detail: 'Larvae become competent + seek substrate. For oysters: setting substrate (microcultch — crushed shell). Larvae attach to substrate. For mussels: similar but on collector ropes.', equipment: 'Setting tanks, microcultch, downwellers', risk: 'Setting failure (larvae don\'t attach); contamination loss' },
      { phase: '5. Spat / seed grow-out (downwelling, 4-8 weeks)', detail: 'Newly-set seed grown in downweller systems (water flows down through seed). Mortality high; need >70% survival to next stage.', equipment: 'Downwellers, fine mesh', risk: 'Mortality from poor water quality; predation; weak seed' },
      { phase: '6. Upweller seed (8-12 weeks)', detail: 'Seed transferred to upweller (water flows up past seed). Allows faster growth. Continuous water exchange. Daily monitoring.', equipment: 'Upweller silos, pumps, fine mesh', risk: 'Pump failure; algal blooms toxic to seed' },
      { phase: '7. Nursery (2-6 months)', detail: 'Seed transferred to floating nursery (FLUPSY = Floating Upweller System). Larger seed grown in higher-flow environment. Mortality drops; survival to 5-15 mm achievable.', equipment: 'FLUPSY system, mesh bags, water pumps', risk: 'Storm damage; mortality events' },
      { phase: '8. Field plant (5-15 mm seed → grow-out gear)', detail: 'Seed transferred to grow-out farm. Stocked in floating cages, bottom cages, or longlines. Growth becomes site-dependent.', equipment: 'Cages, bags, longlines, boat for transport', risk: 'Storm losses; biofouling; predation' },
      { phase: '9. Grow-out (12-30 months)', detail: 'Field-stage. Regular monitoring, biofouling control, density management. Mortality should stabilize <10%/year if conditions good.', equipment: 'Grow-out gear, monitoring tools, harvest boat', risk: 'Disease; mortality events; gear damage' },
      { phase: '10. Pre-harvest depuration (optional, 12-72 hours)', detail: 'For shellfish in conditional waters: held in clean seawater to clear bacteria/contaminants. Required by NSSP for some classifications.', equipment: 'Depuration tanks, UV sterilization, refrigeration', risk: 'Insufficient depuration time; contamination' },
      { phase: '11. Harvest', detail: 'Hauling lines or bags; sorting by size; immediate chilling to <40°F. Speed matters for quality + shelf life.', equipment: 'Hauling equipment, sorting tables, ice/chiller', risk: 'Slow chilling = quality + safety issues' },
      { phase: '12. Post-harvest cold chain', detail: 'Continuous cold (38-40°F) from harvest to consumer. Time-temperature monitoring per NSSP. Sale typically within 24-72 hours.', equipment: 'Refrigerated trucks, walk-in cooler', risk: 'Cold chain break = recalls + safety issues' }
    ];

