      { method: 'Soft-Mesh "Stockings" (Mussel-style)', desc: 'Oysters loaded into mesh socks like mussels. Rare; mostly tried in PNW.', pros: ['Easy to load and harvest', 'Compact gear'], cons: ['Oysters grow uneven', 'Hard to clean'], examples: ['Pacific NW trials'], priceTier: '$$ niche' },
      { method: 'Wild-Set Bottom (Reef Restoration)', desc: 'Cultch shell broadcast on dedicated reef. Wild larvae set naturally. Hybrid restoration/aquaculture.', pros: ['Builds reef habitat', 'No hatchery cost', 'Eligible for restoration grants'], cons: ['Yield unpredictable (depends on wild set)', 'Long timeline', 'May not be commercially viable alone'], examples: ['Penobscot Bay reefs (TNC)'], priceTier: '$$ restoration' }
