    var KELP_PROTOCOL_STEPS = [
      { step: 1, name: 'Wild Spore Collection', month: 'October', detail: 'Harvest mature sporophylls from wild adult Saccharina latissima at offshore "donor" sites. Place in damp burlap and transport to lab within 24 hr to prevent desiccation. Aim for 10 kg of healthy sporophyll tissue per 1 km of seed line you plan to produce.' },
      { step: 2, name: 'Sori Excision', month: 'October', detail: 'In the lab, cut "sori" patches (dark fertile reproductive tissue) from each sporophyll. Rinse in 0.5% iodine solution for 30 sec to surface-sterilize, then triple-rinse in filtered chilled seawater (4°C).' },
      { step: 3, name: 'Spore Release', month: 'October', detail: 'Place sori in 4°C dry darkness for 12-24 hr (osmotic stress). Then submerge in cold filtered seawater. Spores release within 2-4 hr. Count under microscope; target 1000-10000 spores/mL.' },
      { step: 4, name: 'Seed Line Inoculation', month: 'October-November', detail: 'Wind seed twine (1.5 mm polypropylene) onto PVC seed-line spools (100m each). Submerge in spore suspension for 30 min. Spores attach to twine. Transfer to nursery tank.' },
      { step: 5, name: 'Nursery Growth', month: 'November-December', detail: 'Hold seed lines in flow-through tanks at 8-12°C with low-light photoperiod (14:10 light:dark, ~50 µmol photons). Add f/2 nutrient mix weekly. Aerate gently. Sporelings should reach 1-3 mm in 4-6 weeks.' },
      { step: 6, name: 'Quality Check (Pre-Out-Plant)', month: 'December', detail: 'Inspect under microscope. Acceptable: 50+ sporelings per cm of seed twine, 1-3 mm length, no fungal mat. Reject lines with patchy coverage or "fuzz" of contaminating diatoms.' },
      { step: 7, name: 'Out-Plant Day Logistics', month: 'Late December - Early January', detail: 'Truck seed line spools to dock at 4°C. Transfer to vessel. At lease site, attach seed line to grow rope by wrapping around main rope every 10 cm. Use grow rope of 14-16 mm polysteel. Set lines at 1-2 m depth.' },
      { step: 8, name: 'Winter Growth Phase', month: 'January-March', detail: 'Kelp grows slowly at first (4°C water). Inspect monthly: look for biofouling (rare in winter), break ice if collar forms, check anchor lines. Growth accelerates as day length increases.' },
      { step: 9, name: 'Spring Growth Surge', month: 'April-May', detail: 'Kelp grows 1-2 cm/day. Blade length reaches 1-3 m. Sugar content (mannitol) peaks in spring. Inspect for bryozoan biofouling — common after April; harvest before infestation.' },
      { step: 10, name: 'Harvest Timing Decision', month: 'May', detail: 'Harvest before water reaches 10°C (typically late April-May in southern ME, mid-May-June in eastern ME). After 10°C, sporophylls form and blade becomes bitter. Aim for 3-5 kg/m of grow line.' },
      { step: 11, name: 'Harvest Operations', month: 'May', detail: 'Use vessel-mounted hydraulic hauler. Pull grow line; cut kelp at blade base. Pack in shaded totes with ice. Get to processor within 12 hr to maintain "fresh" pricing. Or freeze on-vessel for "frozen-at-sea" tier.' },
      { step: 12, name: 'Post-Harvest Site Care', month: 'May-June', detail: 'Remove all spent grow lines and anchors from site (DMR requirement). Inspect bottom for lost gear. Lower-density "rest" period over summer; replant in October.' }
    ];

