    var SALMON_ASC_STANDARDS = [
      { category: 'Smolt Origin', requirement: 'All juvenile salmon ("smolt") must be from certified hatcheries. Egg-to-smolt traceability required. No wild-source eggs except for breeding-line refresh.', verification: 'Audit hatchery records + DNA sample.' },
      { category: 'Sea Lice Management', requirement: 'Maximum 0.1 adult female lice per fish during the spring out-migration window for wild salmonids (March-June in Maine). Treatments allowed: SLICE (emamectin), Salmosan (azamethiphos), hydrogen peroxide, freshwater wells, lump-sucker biological control.', verification: 'Weekly lice counts on 20 fish per pen, reported publicly.' },
      { category: 'Escapes', requirement: 'Net pens designed for "predator-strong" current and storm conditions. Anti-escape protocols: net inspection weekly, predator nets, double-knot rigging. Every escape event must be reported to ASC + DMR within 24 hr.', verification: 'Net inspection logs + escape reports.' },
      { category: 'Feed Sustainability', requirement: 'Fish-in / fish-out ratio (FIFO) ≤ 1.2 for marine ingredients. Feed must include certified-sustainable fish meal (e.g., IFFO-RS) or 100% trimmings-source.', verification: 'Feed purchase records + supplier certifications.' },
      { category: 'Therapeutic Use', requirement: 'Antibiotics only by prescription; no growth-promotion use. Hormone use prohibited. All use logged + reported.', verification: 'Veterinary records + lab residue testing.' },
      { category: 'Benthic Impact', requirement: 'Benthic monitoring (sediment chemistry, infauna survey) at each site annually. Sites failing must be fallowed until recovery; max 2-yr operation between fallow.', verification: 'Independent benthic survey results filed publicly.' },
      { category: 'Worker Welfare', requirement: 'Minimum wage compliance; safety training documented; ILO core conventions honored; freedom of association protected; child labor prohibited.', verification: 'Worker interviews + payroll audit.' },
      { category: 'Predator Management', requirement: 'Non-lethal predator deterrents required first (acoustic deterrents, predator nets). Lethal removal only as last resort with documented justification.', verification: 'Incident reports + non-lethal effort logs.' },
      { category: 'Site Disease Density', requirement: 'Density limits: standard 25 kg/m³ max; lower for ASC strict tier. Site capacity calculated per benthic carrying capacity model.', verification: 'Periodic stock biomass surveys + benthic model.' },
      { category: 'Community Engagement', requirement: 'Annual community report; complaint mechanism with documented response; engagement with indigenous communities where applicable.', verification: 'Public meeting records + complaint logs.' },
      { category: 'Wild-Salmon Coexistence', requirement: 'Site setback from wild Atlantic salmon migration corridors (Maine rivers with Endangered Species Act listed populations). Genetic-trace monitoring of escapees vs wild stock.', verification: 'NOAA + USFWS coordination; site mapping; escape genetics.' },
      { category: 'Chemical Use Transparency', requirement: 'All chemicals (antifoulants, anesthetics, disinfectants) listed publicly. Copper-based antifoulants restricted; switching to bio-based or copper-low coatings.', verification: 'Chemical inventory + use logs filed annually.' }
    ];

