    var RAS_ENGINEERING = [
      { system: 'Solids Removal — Drum Filter', spec: '60-micron screen, automatic backwash every 2-15 min, capacity 1500-5000 GPM', vendor: 'Hydrotech / PRA / Faivre', cost: '$15-45K per unit', purpose: 'Remove feces, uneaten feed (typically 25-30% of solids load).' },
      { system: 'Solids Removal — Swirl Separator', spec: 'Tangential inlet creates vortex; solids settle in cone bottom; clean water flows from center', vendor: 'Built on-site typically', cost: '$3-10K', purpose: 'Pre-filtration before drum to extend drum life.' },
      { system: 'Biofilter — Moving Bed Bioreactor (MBBR)', spec: 'Plastic media (Kaldnes K1/K3) tumbled by aeration; nitrifying biofilm on media surface', vendor: 'AnoxKaldnes / Veolia', cost: '$50-150K', purpose: 'Convert ammonia (NH3) to nitrate (NO3) via nitrifying bacteria.' },
      { system: 'Biofilter — Trickling Filter', spec: 'Plastic media tower; water trickles over media in air; oxygen + nitrification combined', vendor: 'Various', cost: '$30-80K', purpose: 'Lower-energy alternative to MBBR; tall footprint.' },
      { system: 'CO2 Stripper', spec: 'Counter-current air-water contact column; air-water ratio 8:1; removes dissolved CO2', vendor: 'PRA / Inland Aquaculture', cost: '$15-40K', purpose: 'Fish exhale CO2; high levels suppress growth + cause gill damage.' },
      { system: 'Oxygenator — Low-Head Oxygen Cone', spec: 'Pure O2 injected into pressurized water column; tall narrow vessel; 90%+ transfer efficiency', vendor: 'PRA / DSO', cost: '$10-30K', purpose: 'Supplement dissolved O2 above ambient (10-12 mg/L for fast growth).' },
      { system: 'Oxygenator — Speece Cone', spec: 'Down-flow conical contact chamber; medium pressure', vendor: 'Various', cost: '$8-20K', purpose: 'Alternative O2 supplementation; lower energy.' },
      { system: 'UV Disinfection', spec: '254 nm UV-C; dose 20-40 mJ/cm² for bacteria, 80-150 mJ/cm² for virus; quartz sleeves', vendor: 'Trojan / Atlantic Ultraviolet', cost: '$10-50K', purpose: 'Kill pathogens in circulating water; cannot replace biosecurity.' },
      { system: 'Ozone Treatment', spec: 'Generated from O2 by corona discharge; 0.05-0.5 g/m³ dose; residual destroyed by UV', vendor: 'Mitsubishi Electric / Pacific Ozone', cost: '$30-100K', purpose: 'Oxidize fine particles + color compounds; reduces TSS + BOD.' },
      { system: 'Denitrification Reactor', spec: 'Anoxic chamber with carbon source (methanol or ethanol); converts nitrate to N2 gas', vendor: 'Custom build', cost: '$50-200K', purpose: 'Used in zero-discharge systems; converts accumulated nitrate to harmless N2.' },
      { system: 'Heat Pump / Chiller', spec: 'Water-source heat pump; maintains target temp ±0.5°C; capacity 50-500 kW thermal', vendor: 'Carrier / Trane / heat-pump specialists', cost: '$50-300K', purpose: 'Salmon need 12-15°C; cooling required since metabolic heat raises temp.' },
      { system: 'Backup Generator', spec: 'Diesel generator sized for full life-support load (typically 200-1000 kW); 72-hr fuel reserve', vendor: 'Caterpillar / Kohler / Cummins', cost: '$30-200K', purpose: 'Power loss = fish dead in minutes; backup is non-negotiable.' },
      { system: 'Monitoring System (PLC)', spec: 'Continuous DO, temp, pH, NH3, NO2, ORP sensors; SCADA with remote alerts; redundant probes', vendor: 'Siemens / Allen-Bradley / In-Situ', cost: '$20-100K', purpose: 'Detect failures before fish die; on-call alarms.' },
      { system: 'Feed System (Automatic)', spec: 'Pneumatic blowers; tube routing; demand-feeders or scheduled drops; load cells for portion control', vendor: 'AKVA / Steinsvik', cost: '$30-150K', purpose: 'Precise feed control reduces waste + water quality load.' }
    ];

