    var BIOFILTER_DESIGN = [
      { topic: 'Why Biofilter is Critical', detail: 'Fish excrete ammonia (NH3) through gills. Ammonia is toxic at >0.05 mg/L. Without removal, fish die in days. Biofilter hosts nitrifying bacteria (Nitrosomonas → Nitrobacter) that convert NH3 → NO2 → NO3.' },
      { topic: 'Nitrification Chemistry', detail: 'Step 1 (Nitrosomonas): NH3 + 1.5 O2 → NO2 + H+ + H2O. Step 2 (Nitrobacter): NO2 + 0.5 O2 → NO3. Total O2 consumption: 4.57 mg O2 per mg NH3-N oxidized. Total H+ produced: 1.83 mg per mg NH3-N (drops pH if uncontrolled).' },
      { topic: 'Bacterial Surface Area', detail: 'Nitrifiers grow as biofilm on a surface. Need lots of surface area. MBBR media has 500-1000 m²/m³ of surface area packed in small volume. A typical 1 MT/day RAS biofilter holds 30-100 m³ of media.' },
      { topic: 'Biofilter Sizing Rule', detail: 'Approx 1 m³ of MBBR media per 5-10 kg/day of feed. Or 1 m³ per 30-60 kg of fish biomass. Adjust for water temp (warmer = faster bacteria, smaller filter).' },
      { topic: 'Startup Time', detail: 'Nitrifying bacteria slow-growing. Cold-water RAS: 6-8 weeks to "mature" filter. Add ammonia at 2-5 mg/L daily to feed bacteria during startup. Test daily; filter "mature" when NH3 + NO2 both <0.1 mg/L while ammonia is being added.' },
      { topic: 'Temperature Sensitivity', detail: 'Nitrification slows below 10°C. At 5°C, nitrification rate is ~30% of 25°C rate. RAS for cold-water salmon (12°C target) requires LARGER biofilter than warm-water tilapia (28°C).' },
      { topic: 'Alkalinity Buffer', detail: 'Each mg of ammonia oxidized consumes 7.14 mg alkalinity as CaCO3. Without supplementation, pH drops + nitrification stops. Add NaHCO3 (sodium bicarbonate) continuously. Target alkalinity 100-200 mg/L.' },
      { topic: 'Dissolved Oxygen at Filter', detail: 'Biofilter consumes O2. Maintain >4 mg/L in filter effluent. If filter discharge is anoxic, denitrification + H2S formation occurs.' },
      { topic: 'pH Range', detail: 'Optimal nitrification pH 7.0-8.0. Below 6.5, rate drops 50%. Above 9.0, NH3 (un-ionized) becomes toxic to bacteria itself.' },
      { topic: 'Biofilter Failure Modes', detail: '(1) Power loss → aeration stops → bacteria die from anoxia. (2) Antibiotic in water → nitrifiers killed. (3) Chlorine in makeup water → kills bacteria. (4) Sudden ammonia spike (overfeeding) overwhelms capacity → fish kill.' },
      { topic: 'Denitrification Add-On', detail: 'Closed-loop RAS accumulate nitrate (NO3) — non-toxic but high concentrations slow growth + add disposal cost. Anoxic denitrification reactor with carbon source (methanol) converts NO3 → N2 gas. Reduces water exchange need to near zero.' },
      { topic: 'Biofilter Monitoring', detail: 'Daily test: NH3, NO2, NO3, alkalinity, pH. Weekly: O2 at filter discharge. Trends matter more than single readings.' }
    ];

