    var QUARANTINE_SOP = [
      { step: 1, name: 'Receive Documentation', what: 'Verify all incoming fish/eggs come with: source farm name, health certificate, OIE-listed disease screening results (within 30 days), shipping manifest, hatchery contact info. No paperwork = no acceptance.' },
      { step: 2, name: 'Isolate at Receiving Bay', what: 'Move new arrivals to dedicated quarantine tank with separate water + air supply. No shared equipment with production tanks. Color-code nets, buckets, and tools assigned ONLY to quarantine area.' },
      { step: 3, name: 'Visual Inspection', what: 'Check each individual (or representative sample for large lots) for: fin damage, abnormal swimming, gill discoloration, lesions, scale loss, exophthalmia (popeye), unusual mucus. Record all findings.' },
      { step: 4, name: 'Sample for Pathology', what: 'Sample 5-10% of population (or minimum 30 fish for OIE surveillance). Send to NEVMA or aquaculture pathology lab for: bacterial culture, virus PCR panel (IPN, ISA, IHN, VHS as appropriate), parasite ID (Gyrodactylus, monogeneans).' },
      { step: 5, name: 'Minimum Hold Period', what: 'Hold 30 days minimum, 60 days for new species or new source. Continue daily inspection. Track mortality + behavior.' },
      { step: 6, name: 'Therapeutic Treatments (if needed)', what: 'Common treatments during quarantine: formalin (parasite), oxytetracycline (bacterial), praziquantel (cestode), salt baths (general health). Document all treatments + withdrawal periods.' },
      { step: 7, name: 'Behavior Monitoring', what: 'Daily checks: are fish feeding normally? Schooling? Reacting to disturbance? Any flashing (rubbing against tank walls = parasite)? Any operculum (gill cover) flaring (= gill disease)? Record on standard form.' },
      { step: 8, name: 'Mortality Investigation', what: 'Any mortality during quarantine = STOP. Necropsy each mortality. Hold all remaining stock until cause confirmed. Mortality >2% in 30 days = treat as suspect, send full diagnostic panel.' },
      { step: 9, name: 'Worker Biosecurity', what: 'Anyone entering quarantine area: dedicated boots, gloves, lab coat. Foot dip with quaternary ammonium or iodophor. Hand sanitize before AND after. No multitask with production area.' },
      { step: 10, name: 'Water Discharge Protection', what: 'Quarantine water never mixes with production. Discharge through dedicated drain to disinfection treatment (chlorine, UV, ozone) before release. Solid waste autoclaved or buried.' },
      { step: 11, name: 'Tank Disinfection After Use', what: 'After quarantine release, tank is fully drained, scrubbed with detergent, rinsed, then disinfected with: chlorine 200 ppm for 30 min, OR Virkon S 1% for 10 min, OR iodophor 100 ppm for 30 min. Rinse 3x.' },
      { step: 12, name: 'Records Retention', what: 'Keep all quarantine records 3+ years: source paperwork, health certificate, pathology lab results, treatment log, mortality log, biosecurity audit. Required by ASC + state inspection.' },
      { step: 13, name: 'Transfer Decision', what: 'Transfer to production tank ONLY when: (1) zero mortality past 14 days, (2) negative pathology panel, (3) normal behavior + feeding, (4) tank capacity available. Document approval signature.' }
    ];

