    var COLD_WATER_PROTOCOLS = [
      { phase: '1: Cold Shock Response (0-3 min)', what: 'Initial dunk triggers gasp reflex + hyperventilation. If submerged during gasp, water inhalation = drowning. Heart rate spikes; risk of cardiac arrest in pre-disposed individuals.', mitigation: 'PFD on; surface immediately; protect airway; slow breathing intentionally.' },
      { phase: '2: Cold Incapacitation (3-30 min)', what: 'Loss of fine motor control then gross motor control. Can\'t grip a rope, can\'t self-rescue. Body diverts blood from limbs to core.', mitigation: 'Get out within 10 min. If can\'t, conserve heat: HELP position (Heat Escape Lessening Position — knees to chest).' },
      { phase: '3: Hypothermia (30 min - 2 hr)', what: 'Core temp drops below 95°F. Shivering severe → loss of consciousness around 86°F → cardiac arrest around 82°F.', mitigation: 'Conserve heat; HELP or Huddle position; signal for help.' },
      { phase: '4: Post-Rescue Risk', what: 'Re-warming too fast = "rewarming shock" — cold blood returns to core, can cause cardiac arrest. Survivors may seem fine but die hours later.', mitigation: 'Slow gentle re-warming; cardiac monitoring; medical evaluation always.' },
      { phase: 'HELP Position', what: 'Float on back with PFD. Knees drawn to chest. Hands at neck/jaw. Conserves heat at core; extends survival by 50%+ vs spread position.' },
      { phase: 'Huddle Position', what: '2+ people in water huddle face-to-face with kids in middle. Shared body heat + visibility for rescuers.' },
      { phase: 'Survival Suit Donning', what: 'Practice goal: 60 sec from start to fully sealed + zipped. Untrained: 5+ min. Drill weekly during winter season.' },
      { phase: 'Time-of-Useful-Consciousness', what: '40°F water: 15-30 min useful consciousness, 30-90 min survival. 50°F: 30-60 min useful, 1-3 hr survival. 60°F: 1-2 hr useful, 2-6 hr survival.' },
      { phase: 'Re-Warming Methods', what: 'Mild (>90°F core): warm blankets, warm drinks (no alcohol). Moderate (82-90°F): warm packs to neck/chest/groin, ambulance. Severe (<82°F): ER cardiopulmonary bypass.' },
      { phase: 'Vessel Drills', what: 'Quarterly: muster drill, abandon ship, man-overboard recovery (with dummy). USCG requires drill log for commercial vessels.' }
    ];

