    var SOCIAL_LICENSE = [
      { lesson: 'What is Social License?', detail: 'Beyond legal permits, communities give or withhold tacit approval. Without social license, even legal operations face protests, lawsuits, town vote rejections. American Aquafarms (Frenchman Bay 2022) is the textbook case of losing social license + permit despite legal application path.' },
      { lesson: 'Listen Before Pitching', detail: 'Spend months in community before announcing a project. Attend town meetings as observer. Meet with municipal officials, lobstermen, oysterers, environmental groups, schools. Understand local priorities + concerns.' },
      { lesson: 'Be Visible', detail: 'Office or address in community. Hire local. Sponsor youth sports. Donate to fundraisers. Walk into the diner regularly. Industries that hide behind LLCs face skepticism.' },
      { lesson: 'Public Information Sessions', detail: 'Hold them before formal hearings. Make them informational, not adversarial. Visual aids: maps, photos, simulations. Answer every question, even hostile ones.' },
      { lesson: 'Show, Don\'t Tell', detail: 'Tours of your existing farm or similar operations. Photos of similar sites at scale. Help community see what the proposal really looks like.' },
      { lesson: 'Address Specific Concerns', detail: 'Visual impact — propose specific mitigations (low-profile gear). Lobstering disruption — propose corridors + setbacks. Pollution concerns — show monitoring plans.' },
      { lesson: 'Demonstrate Local Benefit', detail: 'Jobs (with numbers + skill mix), tax base, contributions to community institutions. Demonstrate that benefit will flow to the community, not just the company.' },
      { lesson: 'Show Track Record', detail: 'If you have existing operations elsewhere, share third-party data: environmental monitoring, community surveys, accident history. Don\'t cherry-pick.' },
      { lesson: 'Engage Diverse Voices', detail: 'Indigenous communities (Wabanaki tribes in Maine). Working waterfront fishermen. Environmental advocates. Schools + workforce development. Faith communities. Don\'t just speak to power brokers.' },
      { lesson: 'Long-Term Relationship', detail: 'Social license is renewed daily. Continued communication, transparency, accountability after permitting. Annual community report. Open-house events.' },
      { lesson: 'Mistakes to Avoid', detail: '(1) Sneaking permits through quietly = guaranteed backlash. (2) Hiring outside PR firms to spin = transparent + counterproductive. (3) Threats of lawsuits at first community meeting = ending relationship. (4) Ignoring lobstering tradition + economic realities.' },
      { lesson: 'When Social License Is Withheld', detail: 'Sometimes despite best effort, community is opposed. Listen + reconsider. Sometimes proposal must be modified substantially or withdrawn. Not every site is appropriate.' }
    ];

