    var REGULATORY_TIMELINE = [
      { phase: 'Pre-Application Research (3-6 months)', tasks: 'Site selection + bathymetry survey + water quality baseline + community engagement begin. Hire consultant if needed. Coordinate with DMR pre-application meetings.' },
      { phase: 'Application Drafting (1-3 months)', tasks: 'Formal DMR lease application. Standard lease (10 acre, 10 yr) vs LPA (limited purpose, 1-3 acre). Provide: site map, gear plan, species, methods, business plan, environmental + community assessment.' },
      { phase: 'DMR Initial Review (1-2 months)', tasks: 'DMR staff reviews completeness. May request additional info. Triggers public notice + comment period.' },
      { phase: 'Public Comment Period (30 days)', tasks: 'Notice published in local newspapers + posted at town offices. Anyone can submit written comments. Often the highest-friction phase if community opposed.' },
      { phase: 'Public Hearing (Optional)', tasks: 'If 5+ residents request, public hearing held at town office. Applicant presents; community testifies; DMR + state agencies attend.' },
      { phase: 'DMR Decision (1-3 months post-hearing)', tasks: 'DMR Commissioner evaluates: ecological impact, navigational impact, public access, social compatibility. Issues written decision.' },
      { phase: 'Federal Coordination (Concurrent)', tasks: 'Army Corps of Engineers permit for structures in navigable waters. NOAA + USFWS consult on Endangered Species Act impacts (Atlantic salmon habitat). EPA NPDES if discharge.' },
      { phase: 'Lease Issued', tasks: 'If approved, lease is signed. Standard 10-year term, renewable. Annual lease fee ($50-200 per acre). Performance bonds may be required.' },
      { phase: 'Pre-Operations Compliance', tasks: 'Notify USCG for navigational lighting. NSSP shellfish growing area designation (DMR Shellfish Sanitation). HACCP plan for processing.' },
      { phase: 'Operations Start', tasks: 'Begin gear deployment. Maintain daily records: stock, mortality, water quality, harvest. Monthly reports to DMR.' },
      { phase: 'Annual Compliance', tasks: 'Annual report to DMR. Renew shellfish certification. Update biotoxin testing. Renew operator licenses.' },
      { phase: 'Lease Renewal (Year 9-10)', tasks: 'Renewal application 6+ months before expiration. Demonstrate compliance + community support continues.' },
      { phase: 'Termination / Site Decommission', tasks: 'Remove all gear; restore site; final inspection by DMR. Bond release.' }
    ];

