    var DEEP_GLOSSARY = [
      { term: 'Adductor Muscle', def: 'The muscle that closes a bivalve shell. The "scallop" we eat is just the adductor.' },
      { term: 'Anoxic', def: 'No dissolved oxygen. Anoxic sediment beneath aquaculture sites = stress + bad chemistry.' },
      { term: 'Antifoulant', def: 'Coating applied to nets + gear to prevent marine organism attachment (bryozoans, tunicates, hydroids).' },
      { term: 'Astaxanthin', def: 'Red carotenoid pigment. Wild salmon get from krill diet. Farmed salmon need supplemented in feed for pink color.' },
      { term: 'AZE (Allowable Zone of Effect)', def: 'Permit-defined area around aquaculture site where benthic impact is acceptable. Beyond AZE, conditions must match reference.' },
      { term: 'Backwash', def: 'Reverse-flow cleaning of drum filter or sand filter to remove accumulated solids.' },
      { term: 'Biofouling', def: 'Accumulation of organisms (algae, bryozoans, tunicates, mussels) on gear surfaces. Reduces flow + increases drag.' },
      { term: 'Biofloc', def: 'Heterotrophic bacterial flocs in aquaculture water that consume ammonia + organic matter + provide supplemental nutrition.' },
      { term: 'Broodstock', def: 'Mature reproductive animals selected to spawn for next generation. Triploid oyster broodstock is tetraploid; mussel + kelp broodstock often wild-collected.' },
      { term: 'Bryozoan', def: 'Colonial filter-feeding invertebrate (Membranipora is the kelp-killer). Encrusts surfaces in lacy patterns.' },
      { term: 'Carrying Capacity', def: 'Maximum standing stock a site can support without negative effects on benthos or water quality. Calculated by hydrographic + benthic models.' },
      { term: 'Cement Gland (Oyster)', def: 'Foot gland that secretes shell-attaching cement at metamorphosis. One-time attachment.' },
      { term: 'Chlorophyll a', def: 'Photosynthetic pigment in phytoplankton. Indicator of primary productivity + algal bloom potential.' },
      { term: 'Copepodid', def: 'Infective larval stage of sea lice that attaches to fish. Free-swimming + critical management target.' },
      { term: 'Cultch', def: 'Old oyster shell broadcast on the seabed to provide attachment substrate for natural larval settlement.' },
      { term: 'Denitrification', def: 'Anoxic biological conversion of nitrate (NO3) to N2 gas. Used in zero-discharge RAS systems.' },
      { term: 'DEBY', def: 'Disease Resistant Eastern oyster broodstock line bred at Virginia Institute of Marine Science. Resists Dermo + MSX.' },
      { term: 'Diploid', def: 'Normal chromosomal count (2 sets) in most oysters. Wild oysters are diploid. Most farmed premium oysters are triploid.' },
      { term: 'DMR', def: 'Maine Department of Marine Resources. State agency overseeing aquaculture leases, fisheries, shellfish sanitation.' },
      { term: 'Drogue', def: 'Anchor-like underwater drag device that floats at desired depth to slow movement. Used in current-mapping studies.' },
      { term: 'Eelgrass (Zostera marina)', def: 'Native seagrass. Habitat for juvenile fish + scallops. Sensitive to light + nutrient changes from aquaculture.' },
      { term: 'EPIRB', def: 'Emergency Position Indicating Radio Beacon. 406 MHz satellite distress beacon mounted on vessel.' },
      { term: 'FCR (Feed Conversion Ratio)', def: 'Kg feed needed per kg of fish growth. Salmon FCR ~1.0-1.3 is best of any farmed animal protein.' },
      { term: 'FIFO (Fish-In / Fish-Out)', def: 'Ratio of wild-caught fish ingredients in feed to farmed fish output. ASC target: <1.2 for salmon.' },
      { term: 'Foot Print', def: 'Physical bottom area occupied by aquaculture gear. Important for benthic monitoring + comparison to natural variability.' },
      { term: 'FlipFarm', def: 'New Zealand-designed hexagonal cage that auto-rotates around longline. Reduces biofouling labor.' },
      { term: 'GAA / BAP', def: 'Global Aquaculture Alliance / Best Aquaculture Practices. Third-party sustainability certification.' },
      { term: 'GMRI', def: 'Gulf of Maine Research Institute (Portland). Marine research + education nonprofit; major regional player.' },
      { term: 'GMP (Good Manufacturing Practices)', def: 'FDA-defined food production standards. Required for processed seafood.' },
      { term: 'HABs (Harmful Algal Blooms)', def: 'Blooms of toxic phytoplankton (Alexandrium, Pseudo-nitzschia, Dinophysis). Trigger NSSP shellfish closures.' },
      { term: 'HACCP', def: 'Hazard Analysis Critical Control Point food safety plan. Required for all FDA-regulated seafood processors.' },
      { term: 'Hatchery', def: 'Facility where larval stages are produced + reared to juvenile stage for transfer to grow-out.' },
      { term: 'Heat Pump (Aquaculture)', def: 'Water-source heat pump used to maintain target temp in RAS systems. Salmon need active cooling.' },
      { term: 'HDPE', def: 'High Density Polyethylene. Plastic for net pen rings, cage frames, longlines.' },
      { term: 'HELP Position', def: 'Heat Escape Lessening Position. Cold-water survival posture: knees-to-chest, arms-folded.' },
      { term: 'IMTA', def: 'Integrated Multi-Trophic Aquaculture. Combining species from different trophic levels at one site.' },
      { term: 'IPN (Infectious Pancreatic Necrosis)', def: 'Salmonid virus. Vaccinated against pre-smolt.' },
      { term: 'ISA (Infectious Salmon Anemia)', def: 'Salmonid virus causing high mortality. Subject of vaccination + biosecurity programs.' },
      { term: 'Knot (Vessel Speed)', def: 'One nautical mile per hour (1.85 km/hr). Aquaculture vessels typically operate 6-15 knots.' },
      { term: 'Lease (Maine)', def: 'DMR-issued right to use submerged lands for aquaculture. Standard 10-acre 10-year vs LPA (Limited Purpose Aquaculture, 1-3 acre 3-year).' },
      { term: 'Lobster Boat', def: 'Versatile Maine working boat (28-45ft); used for lobster fishery + many aquaculture operations.' },
      { term: 'Longline', def: 'Horizontal line suspended in water from which cages, socks, or bags hang.' },
      { term: 'LPA', def: 'Limited Purpose Aquaculture lease in Maine. 1-3 acres, 3-year. Faster permitting; lower-impact threshold.' },
      { term: 'Mannitol', def: 'Sugar alcohol in kelp (especially sugar kelp). Sweet flavor; peak in spring; declines in summer.' },
      { term: 'MBBR', def: 'Moving Bed Bioreactor. Biofilter with plastic media tumbled by aeration. Standard RAS biofilter.' },
      { term: 'MMPA', def: 'Marine Mammal Protection Act. Restricts lethal control of seals + whales + dolphins.' },
      { term: 'MSX (Multinucleated Sphere X)', def: 'Oyster disease (Haplosporidium nelsoni) that devastated mid-Atlantic oyster industry. DEBY oysters bred to resist.' },
      { term: 'Mussel Sock', def: 'Cylindrical cotton or polypropylene mesh tube filled with mussel seed. Hung from raft or longline for grow-out.' },
      { term: 'NERACOOS', def: 'Northeastern Regional Association of Coastal Ocean Observing Systems. Buoy + monitoring network.' },
      { term: 'Nitrification', def: 'Aerobic biological conversion of ammonia → nitrite → nitrate by bacteria. Core RAS process.' },
      { term: 'NSSP', def: 'National Shellfish Sanitation Program. Federal-state program ensuring shellfish food safety.' },
      { term: 'Off-Bottom Culture', def: 'Aquaculture gear lifted from seabed (cages, longlines, rafts). Better predator + biofouling control.' },
      { term: 'OysterGro', def: 'Brand of floating oyster cage with pontoons. Common in Maine.' }
    ];

