    var TECHNICAL_GLOSSARY = [
      { term: 'PFD (Personal Flotation Device)', def: 'USCG-classified life jacket. Types I-V; Type I is offshore-grade.' },
      { term: 'Ploidy', def: 'Number of chromosome sets. Diploid = 2; triploid = 3; tetraploid = 4. Triploid oysters dominate premium markets.' },
      { term: 'pH', def: 'Hydrogen ion concentration measure. Marine seawater normally 7.5-8.4. Drop = acidification.' },
      { term: 'Phytoplankton', def: 'Microscopic plant-like organisms; base of marine food web; primary food for bivalves + larval fish.' },
      { term: 'Polysteel', def: 'High-strength polyester-coated steel rope used in aquaculture longlines + mooring.' },
      { term: 'PSP (Paralytic Shellfish Poisoning)', def: 'Biotoxin from Alexandrium dinoflagellate. Saxitoxins. Triggers NSSP closures.' },
      { term: 'Pteropod', def: 'Sea butterfly; calcium-shelled plankton sensitive to ocean acidification. Indicator species.' },
      { term: 'Quahog', def: 'Hard-shell clam (Mercenaria mercenaria); the chowder clam.' },
      { term: 'RAS (Recirculating Aquaculture System)', def: 'Land-based closed-loop fish farming with biofilter, oxygenation, water treatment.' },
      { term: 'Recirculation Rate', def: 'Volume of system water passed through life-support per unit time. Typically 1-2 full turnovers per hour.' },
      { term: 'Reef-Built (Oyster)', def: 'Wild + restored oyster reefs that create complex 3D habitat structure on seabed.' },
      { term: 'Salinity', def: 'Salt concentration in water; typically measured in parts per thousand (ppt). Marine 30-35; estuarine 15-30; brackish 5-15; fresh <5.' },
      { term: 'Salmonella', def: 'Bacterial genus; not typically aquaculture concern but tracked in food safety.' },
      { term: 'Sea Lice (Lepeophtheirus salmonis)', def: 'Parasitic copepod on Atlantic salmon. Major management challenge in salmon farming.' },
      { term: 'Seine', def: 'Encircling net used to capture fish.' },
      { term: 'Settlement (Larval)', def: 'Process of larval transition from planktonic to attached/benthic form. One-time-only for oysters.' },
      { term: 'Shellfish Sanitation', def: 'NSSP-coordinated state-federal program ensuring shellfish food safety.' },
      { term: 'Skeleton (RAS)', def: 'Structural framework of a recirculating system; can become microbial reservoir.' },
      { term: 'Slow Sand Filter', def: 'Biological filtration method using sand media; emerging RAS application.' },
      { term: 'SPF (Specific Pathogen Free)', def: 'Broodstock verified to be free of specific pathogens. Essential for shrimp + many fish industries.' },
      { term: 'Stock Density', def: 'Mass of farmed animals per unit volume. Salmon target ~25 kg/m³.' },
      { term: 'Stratification', def: 'Vertical layering of water by temperature or salinity. Summer surface warmer; deep cooler.' },
      { term: 'Subtidal', def: 'Always submerged below low tide level.' },
      { term: 'TAN (Total Ammonia Nitrogen)', def: 'Sum of un-ionized NH3 + ionized NH4. NH3 portion increases with pH + temperature.' },
      { term: 'Thermocline', def: 'Sharp temperature gradient in water column. Limits mixing + nutrient exchange.' },
      { term: 'Triploid', def: 'Oyster with 3 sets of chromosomes; cannot reproduce; diverts energy to meat growth.' },
      { term: 'Trochophore', def: 'First larval stage in oysters; free-swimming with cilia band.' },
      { term: 'TSS (Total Suspended Solids)', def: 'Particulate matter in water; mg/L. Critical RAS metric.' },
      { term: 'Tunicate (Sea Squirt)', def: 'Marine invertebrate; can fouling pest on aquaculture gear.' },
      { term: 'UV-C', def: 'Short-wavelength UV (254 nm); disinfects water by destroying microbial DNA.' },
      { term: 'Veliger', def: 'Bivalve larval stage with shell + velum (feeding organ).' },
      { term: 'Vibrio parahaemolyticus', def: 'Bacteria; marine. Causes gastroenteritis. FDA Vp Control Plan covers summer shellfish.' },
      { term: 'VHF Marine Radio', def: 'Very High Frequency radio for vessel-to-vessel + emergency communication. Ch 16 distress.' },
      { term: 'Vinalhaven', def: 'Maine island town; home of Hurricane Island Center for Science + Leadership.' },
      { term: 'Wabanaki', def: 'Confederacy of indigenous nations of Maine + Maritimes — Passamaquoddy, Penobscot, Mi\'kmaq, Maliseet, Abenaki.' },
      { term: 'Wakame (Undaria pinnatifida)', def: 'Asian seaweed; INVASIVE in US; not recommended for Maine cultivation.' },
      { term: 'Working Waterfront', def: 'Coastal property used for commercial maritime activity. Politically protected category in Maine.' },
      { term: 'WCAG', def: 'Web Content Accessibility Guidelines (digital accessibility) — relevant for marketing material accessibility.' },
      { term: 'Xiphosura', def: 'Horseshoe crab order; not aquaculture commercial but bait + ecology.' },
      { term: 'YOY (Young of Year)', def: 'Fish in first year of life. Important survival metric for hatchery operations.' },
      { term: 'Zoea', def: 'Crab + shrimp larval stage. Free-swimming.' },
      { term: 'Zooxanthellae', def: 'Symbiotic algae in corals + some bivalves. Not significant in Maine cold-water aquaculture.' }
    ];

