    var CLIMATE_DEEP_DIVE = [
      { topic: 'Gulf of Maine Warming Rate', detail: 'The Gulf of Maine is warming faster than 99% of the world\'s oceans (Pershing et al., 2015 Science). Mean surface temperature increased ~0.06°C per year from 2004-2013, vs ~0.01°C/yr global average. Recent years continue + may accelerate.' },
      { topic: 'Driver: Shifting Labrador Current', detail: 'GOM water historically supplied by cold Labrador Current. Recent oceanographic shift: more warm Gulf Stream-derived "slope water" enters GOM through Northeast Channel; less cold Labrador. Driver: shifting Atlantic Meridional Overturning Circulation (AMOC).' },
      { topic: 'Species Range Shifts — Lobster Northward', detail: 'American lobster population center moved 50+ miles north over 20 years. Southern Maine has decline; northern Maine + Maritimes had peak landings 2010s. Continued northward shift expected.' },
      { topic: 'Species Range Shifts — Southern Species Arriving', detail: 'Black sea bass, summer flounder, blue crab, mid-Atlantic species are appearing more frequently in Maine. Fisheries + aquaculture may need to adapt species mix.' },
      { topic: 'Sea Urchin Collapse + Non-Recovery', detail: 'Maine green sea urchin (Strongylocentrotus droebachiensis) crashed 1990s; has not recovered. Possible factors: overfishing + warming + predator shifts.' },
      { topic: 'Soft-Shell Clam Decline', detail: 'Invasive European green crab (Carcinus maenas) population exploded with warming water 2010+. Devastates juvenile soft-shell clams. Maine wild clam fishery in steep decline; some towns have lost industry.' },
      { topic: 'Atlantic Salmon Crisis', detail: 'Wild Atlantic salmon in Maine rivers ESA listed (endangered) since 2000. Population continues to decline despite habitat work. Climate (warming smolts encounter) + fishing + dams all contribute.' },
      { topic: 'Ocean Acidification Trend', detail: 'GOM pH has declined ~0.1 units since pre-industrial (more acidic). Projected to continue. Particular concern for shellfish hatcheries — early larvae sensitive. Mook Sea Farm has pioneered acidification research.' },
      { topic: 'Hatchery Pier Buffer System (Mook)', detail: 'Bill Mook installed pier-side buffer that monitors incoming water + adjusts pH + alkalinity before flowing to larval tanks. Industry-leading adaptation.' },
      { topic: 'Phenology Shifts', detail: 'Seasonal timing shifting. Spring + fall arriving earlier. Affects spawning + larval-survival + food-web matching. Aquaculture protocols (kelp seed timing, oyster spawn) must adapt.' },
      { topic: 'Coastal Storm Frequency + Intensity', detail: 'Sea level rise + storm-surge intensification. 2018 + 2022 bomb cyclones caused significant aquaculture gear damage. Storm-rated gear + insurance increasingly important.' },
      { topic: 'Adaptation Strategies — Site Selection', detail: 'New farms increasingly select cooler/deeper sites to buffer warming. Offshore submerged gear less affected by surface heat extremes.' },
      { topic: 'Adaptation Strategies — Species Mix', detail: 'Climate-resilient species (kelp, mussels in winter) gaining attention. Salmon may need to be moved further north long-term.' },
      { topic: 'Adaptation Strategies — Selective Breeding', detail: 'Climate-resilient broodstock selection: heat-tolerant oyster lines, acidification-resistant mussel strains. Active research at UMaine + Bigelow.' },
      { topic: 'Mitigation: Kelp + Shellfish Carbon Service', detail: 'Aquaculture can be part of climate solution. Kelp + bivalves remove CO2 + nitrogen from water. Bigelow + GMRI research carbon-sequestration role. Possible blue carbon credit market.' },
      { topic: 'Coastal Erosion + Sea Level', detail: 'Maine sea level rising ~3 mm/yr. Over 30-year lease = ~10 cm. Affects intertidal-zone aquaculture (clam flats, mussel rafts at low tide). Long-term lease + capital decisions must factor.' },
      { topic: 'Plankton Community Shifts', detail: 'Warming + acidification shift phytoplankton + zooplankton communities. Affects bivalve food supply + larval fish survival. Aquaculture must adapt to changing food-web composition.' },
      { topic: 'Harmful Algal Bloom Increase', detail: 'PSP + DSP blooms appear to be increasing in frequency + range. Pseudo-nitzschia + Dinophysis blooms not historically common; now annual events.' },
      { topic: 'Industry Risk Disclosure', detail: 'Insurance + investors increasingly demand climate-risk disclosure. Salmon farms reporting on water-temperature trends + adaptation plans.' },
      { topic: 'Workforce Adaptation', detail: 'As lobster shifts north, southern Maine fishing communities face economic decline. Aquaculture pitched as transition crop. UMaine + Sea Grant programs support transition.' }
    ];

